from prometheus_client import start_http_server, Counter
import http.server
import socketserver

# Prometheus metrics setup
user_path_counter = {}

class MyHttpRequestHandler(http.server.SimpleHTTPRequestHandler):
    def do_GET(self):
        # Extract user_id and session_id from headers or cookies if available
        user_id = self.headers.get('X-User-ID', 'unknown')
        session_id = self.headers.get('X-Session-ID', 'unknown')

        # Create a unique label for each user-path combination
        user_path_label = f"{user_id}_{self.path}"

        # Update or create the counter for this specific user-path combination
        if user_path_label not in user_path_counter:
            user_path_counter[user_path_label] = Counter(f"http_requests_total_user_{user_id}_path_{self.path}", 'HTTP request total', ['user_id', 'session_id', 'path'])
        
        # Increment the counter for this request
        user_path_counter[user_path_label].labels(user_id=user_id, session_id=session_id, path=self.path).inc()

        # Call superclass method to handle actual HTTP request processing
        super().do_GET()

# Setup Prometheus metrics server on port 8000
start_http_server(8000)

# Define the server address and port
PORT = 8001

# Create an HTTP server with the custom handler
with socketserver.TCPServer(("", PORT), MyHttpRequestHandler) as httpd:
    print(f"Serving at port {PORT}")
    # Serve requests indefinitely
    httpd.serve_forever()